#include <stdio.h>
#include <stdlib.h>
#include <string.h>

void construct(int n, char *out) {
    if (n == 2) {
        out[0] = 'a'; out[1] = 'b'; out[2] = '\0';
        return;
    }
    if (n % 2 == 1) {
        int half = (n - 1) / 2;
        memset(out, 'a', half);
        out[half] = 'b';
        memset(out + half + 1, 'a', half);
        out[n] = '\0';
    } else {
        int half = n / 2;
        int i;
        for (i = 0; i < half - 1; ++i) out[i] = 'a';
        out[half - 1] = 'b';
        // copy reverse
        for (i = 0; i < half; ++i) out[half + i] = out[half - 1 - i];
        out[n] = '\0';
    }
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        char *s = (char*)malloc(N + 1);
        construct(N, s);
        printf("%s\n", s);
        free(s);
    }
    return 0;
}

