#include <bits/stdc++.h>
using namespace std;

string construct(int n) {
    if (n == 2) return "ab";
    if (n % 2 == 1) {
        int half = (n - 1) / 2;
        return string(half, 'a') + 'b' + string(half, 'a');
    } else {
        int half = n / 2;
        string first(half - 1, 'a');
        first.push_back('b');
        string second = first;
        reverse(second.begin(), second.end());
        return first + second;
    }
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while (T--) {
        int N; cin >> N;
        cout << construct(N) << '\n';
    }
    return 0;
}

