import java.io.*;
import java.util.*;

public class Main {
    private static String construct(int n) {
        if (n == 2) return "ab";
        if ((n & 1) == 1) {
            int half = (n - 1) / 2;
            char[] arr = new char[n];
            Arrays.fill(arr, 'a');
            arr[half] = 'b';
            return new String(arr);
        } else {
            int half = n / 2;
            char[] first = new char[half];
            Arrays.fill(first, 0, half - 1, 'a');
            first[half - 1] = 'b';
            char[] second = new char[half];
            for (int i = 0; i < half; i++) second[i] = first[half - 1 - i];
            return new String(first) + new String(second);
        }
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder out = new StringBuilder();
        int T = Integer.parseInt(br.readLine().trim());
        for (int t = 0; t < T; t++) {
            int N = Integer.parseInt(br.readLine().trim());
            out.append(construct(N)).append('\n');
        }
        System.out.print(out.toString());
    }
}

