#!/usr/bin/env python3
import sys

def construct(n: int) -> str:
    if n == 2:
        return "ab"
    if n % 2 == 1:
        half = (n - 1) // 2
        return "a" * half + "b" + "a" * half
    half = n // 2
    first = "a" * (half - 1) + "b"
    return first + first[::-1]

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    t = int(data[0])
    idx = 1
    out_lines = []
    for _ in range(t):
        n = int(data[idx]); idx += 1
        out_lines.append(construct(n))
    sys.stdout.write("\n".join(out_lines))

if __name__ == "__main__":
    main()

