let results = [];
function construct(n) {
  if (n === 2) return 'ab';
  if (n % 2 === 1) {
    const half = (n - 1) >> 1;
    return 'a'.repeat(half) + 'b' + 'a'.repeat(half);
  }
  const half = n >> 1;
  const first = 'a'.repeat(half - 1) + 'b';
  const second = first.split('').reverse().join('');
  return first + second;
}
